140	/// A helper class to manage the underlying memory buffer used by
141	/// 'RecordLogParser'. For container types, i.e. composite records, the buffer
142	/// acts as outer vector with pointers to inner buffers.
143	class BufferHandler {
144	public:
145	  BufferHandler() = default;
146	  ~BufferHandler() = default;
147	  /// Copying and assignment not permitted
148	  BufferHandler(BufferHandler &other) = delete;
149	  BufferHandler &operator=(BufferHandler &other) = delete;
150	  BufferHandler(const BufferHandler &) = delete;
151	  BufferHandler &operator=(const BufferHandler &) = delete;
152	  BufferHandler(BufferHandler &&) = default;
153	  BufferHandler &operator=(BufferHandler &&) = default;
154	
155	  void *getBufferPtr() const {
156	    return reinterpret_cast<void *>(const_cast<char *>(buffer.data()));
157	  }
158	
159	  std::size_t getBufferSize() const { return buffer.size(); }
160	
161	  void resizeBuffer(std::size_t more) { buffer.resize(buffer.size() + more); }
162	
163	  template <typename T>
164	  void addPrimitiveRecord(T value) {
165	    std::size_t position = buffer.size();
166	    buffer.resize(position + sizeof(T));
167	    std::memcpy(buffer.data() + position, &value, sizeof(T));
168	  }
169	
170	  template <typename T>
171	  size_t allocateArrayRecord(size_t arrSize) {
172	    size_t vectorOffset = buffer.size();
173	    if constexpr (std::is_same_v<T, bool>) {
174	      auto *allocation = new std::vector<bool>(arrSize);
175	      if (!allocation)
176	        throw std::runtime_error("Memory allocation failed");
177	      auto byteLength = sizeof(*allocation);
178	      buffer.resize(vectorOffset + byteLength);
179	      std::memcpy(buffer.data() + vectorOffset, allocation, byteLength);
180	      return vectorOffset;
181	    }
182	
183	    buffer.resize(vectorOffset + 3 * sizeof(T *));
184	    size_t byteLength = arrSize * sizeof(T);
185	    T *innerBuffer = static_cast<T *>(malloc(byteLength));
186	    if (!innerBuffer)
187	      throw std::runtime_error("Memory allocation failed");
188	    std::memset(innerBuffer, 0, byteLength);
189	    /// Initialize the three pointers of the inner vector
190	    T *startPtr = innerBuffer;
191	    T *end0Ptr = innerBuffer + arrSize;
192	    T *end1Ptr = end0Ptr;
193	    /// Store the pointers into the outer vector (buffer) without assuming the
194	    /// byte offset is suitably aligned for a T** access.
195	    T *pointers[] = {startPtr, end0Ptr, end1Ptr};
196	    std::memcpy(buffer.data() + vectorOffset, pointers, sizeof(pointers));
197	    return vectorOffset;
198	  }
199	
200	  template <typename T>
201	  void insertIntoArray(size_t offset, std::size_t index, T value) {
202	    if constexpr (std::is_same_v<T, bool>) {
203	      auto *v = reinterpret_cast<std::vector<bool> *>(buffer.data() + offset);
204	      (*v)[index] = value;
205	    } else {
206	      T *innerBuffer = nullptr;
207	      std::memcpy(&innerBuffer, buffer.data() + offset, sizeof(innerBuffer));
208	      innerBuffer[index] = value;
209	    }
210	  }
