212	  /// NOTE: This is used only if data layout (alignment) is missing
213	  template <typename T>
214	  size_t allocateTupleRecord() {
215	    size_t position = buffer.size();
216	    buffer.resize(position + sizeof(T));
217	    return position;
218	  }
