220	  template <typename T>
221	  void insertIntoTuple(size_t offset, T value) {
222	    if (offset > buffer.size() || sizeof(T) > buffer.size() - offset)
223	      throw std::runtime_error("Tuple element exceeds result buffer");
224	    std::memcpy(buffer.data() + offset, &value, sizeof(T));
225	  }
