55	/// Greedy pass to match subgraphs in the IR and replace them with codegen ops.
56	/// This step makes converting a DAG of nodes in the conversion step simpler.
57	static LogicalResult fuseSubgraphPatterns(MLIRContext *ctx, ModuleOp module) {
58	  RewritePatternSet patterns(ctx);
59	  cudaq::codegen::populateQuakeToCodegenPatterns(patterns);
60	  LLVM_DEBUG(llvm::dbgs() << "Before codegen dialect:\n"; module.dump());
61	  if (failed(applyPatternsGreedily(module, std::move(patterns))))
62	    return failure();
63	  LLVM_DEBUG(llvm::dbgs() << "After codegen dialect:\n"; module.dump());
64	  return success();
