67	namespace {
68	/// Convert Quake dialect to LLVM-IR and QIR.
69	class ConvertToQIR : public cudaq::opt::impl::ConvertToQIRBase<ConvertToQIR> {
70	public:
71	  using ConvertToQIRBase::ConvertToQIRBase;
72	
73	  /// Measurement counter for unnamed measurements. Resets every module.
74	  unsigned measureCounter = 0;
75	
76	  // This is an ad hoc transformation to convert constant array values into a
77	  // buffer of constants.
78	  LogicalResult eraseConstantArrayOps() {
79	    bool ok = true;
80	    SmallVector<Operation *> cleanUps;
81	    getOperation().walk([&](cudaq::cc::ConstantArrayOp carr) {
82	      // If there is a constant array, then we expect that it is involved in
83	      // a stdvec initializer expression. So look for the pattern and expand
84	      // the store into a series of scalar stores.
85	      //
86	      //   %100 = cc.const_array [c1, c2, ... cN] : ...
87	      //   %110 = cc.alloca ...
88	      //   cc.store %100, %110 : ...
89	      //   __________________________
90	      //
91	      //   cc.store c1, %110[0]
92	      //   cc.store c2, %110[1]
93	      //   ...
94	      //   cc.store cN, %110[N-1]
95	
96	      // Are all uses the value to a store?
97	      if (!std::all_of(carr->getUsers().begin(), carr->getUsers().end(),
98	                       [&](auto *op) {
99	                         auto st = dyn_cast<cudaq::cc::StoreOp>(op);
100	                         return st && st.getValue() == carr.getResult();
101	                       })) {
102	        ok = false;
103	        return;
104	      }
105	
106	      auto eleTy = cast<cudaq::cc::ArrayType>(carr.getType()).getElementType();
107	      auto ptrTy = cudaq::cc::PointerType::get(eleTy);
108	      auto loc = carr.getLoc();
109	
110	      for (auto *user : carr->getUsers()) {
111	        auto origStore = cast<cudaq::cc::StoreOp>(user);
112	        OpBuilder builder(origStore);
113	        auto buffer = origStore.getPtrvalue();
114	        const std::int32_t numConstants = carr.getConstantValues().size();
115	        auto constantValues = carr.getConstantValues();
116	        for (std::int32_t idx = 0; idx < numConstants; idx++) {
117	          auto v = [&]() -> Value {
118	            auto val = constantValues[idx];
119	            if (auto fTy = dyn_cast<FloatType>(eleTy))
120	              return arith::ConstantFloatOp::create(
121	                  builder, loc, fTy, cast<FloatAttr>(val).getValue());
122	            if (auto iTy = dyn_cast<IntegerType>(eleTy))
123	              return arith::ConstantIntOp::create(
124	                  builder, loc, iTy, cast<IntegerAttr>(val).getInt());
125	            auto cTy = cast<ComplexType>(eleTy);
126	            return complex::ConstantOp::create(builder, loc, cTy,
127	                                               cast<ArrayAttr>(val));
128	          }();
129	          Value arrWithOffset = cudaq::cc::ComputePtrOp::create(
130	              builder, loc, ptrTy, buffer,
131	              ArrayRef<cudaq::cc::ComputePtrArg>{idx});
132	          cudaq::cc::StoreOp::create(builder, loc, v, arrWithOffset);
133	        }
134	        cleanUps.push_back(user);
135	      }
136	      cleanUps.push_back(carr.getOperation());
137	    });
138	
139	    for (auto *op : cleanUps) {
140	      op->dropAllUses();
141	      op->erase();
142	    }
143	    return ok ? success() : failure();
144	  }
145	
146	  /// Greedy pass to match subgraphs in the IR and replace them with codegen
147	  /// ops. This step makes converting a DAG of nodes in the conversion step
148	  /// simpler.
149	  void runOnOperation() override final {
150	    auto *context = &getContext();
151	    if (failed(fuseSubgraphPatterns(context, getOperation()))) {
152	      signalPassFailure();
153	      return;
154	    }
155	    // Ad hoc deal with ConstantArrayOp transformation.
156	    // TODO: Merge this into the codegen dialect once that gets to main.
157	    if (failed(eraseConstantArrayOps())) {
158	      getOperation().emitOpError("unexpected constant arrays");
159	      signalPassFailure();
160	      return;
161	    }
162	
163	    LLVMConversionTarget target{*context};
164	    LLVMTypeConverter typeConverter(&getContext());
165	    cudaq::opt::initializeTypeConversions(typeConverter);
166	    RewritePatternSet patterns(context);
167	
168	    populateComplexToLibmConversionPatterns(patterns, 1);
169	    populateComplexToLLVMConversionPatterns(typeConverter, patterns);
170	
171	    arith::populateCeilFloorDivExpandOpsPatterns(patterns);
172	    arith::populateArithToLLVMConversionPatterns(typeConverter, patterns);
173	    populateMathToLLVMConversionPatterns(typeConverter, patterns);
174	
175	    cf::populateControlFlowToLLVMConversionPatterns(typeConverter, patterns);
176	    populateFuncToLLVMConversionPatterns(typeConverter, patterns);
177	    cudaq::opt::populateCCToLLVMPatterns(typeConverter, patterns);
178	    cudaq::opt::populateQuakeToLLVMPatterns(typeConverter, patterns,
179	                                            measureCounter);
180	    target.addLegalDialect<LLVM::LLVMDialect>();
181	    target.addLegalOp<ModuleOp>();
182	
183	    auto op = getOperation();
184	    LLVM_DEBUG(llvm::dbgs() << "Before conversion to QIR:\n"; op.dump());
185	    if (failed(applyFullConversion(op, target, std::move(patterns)))) {
186	      LLVM_DEBUG(getOperation().dump());
187	      signalPassFailure();
188	    }
189	    LLVM_DEBUG(llvm::dbgs() << "After conversion to QIR:\n"; op.dump());
190	  }
191	};
