31	static void addQIRConversionPipeline(PassManager &pm, StringRef convertTo) {
32	  auto convertFields = convertTo.split(':');
33	  if (convertFields.first == "qir" || convertFields.first == "qir-full") {
34	    cudaq::opt::addConvertToQIRAPIPipeline(pm, "full:" +
35	                                                   convertFields.second.str());
36	  } else if (convertFields.first == "qir-base") {
37	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createDelayMeasurements());
38	    cudaq::opt::addConvertToQIRAPIPipeline(pm, "base-profile:" +
39	                                                   convertFields.second.str());
40	  } else if (convertFields.first == "qir-adaptive") {
41	    cudaq::opt::addConvertToQIRAPIPipeline(pm, "adaptive-profile:" +
42	                                                   convertFields.second.str());
43	  } else {
44	    emitError(UnknownLoc::get(pm.getContext()),
45	              "convert to QIR must be given a valid specification to use.");
46	  }
47	}
