97	template <bool isJIT, bool useValueSemantics = false>
98	void createTargetCodegenPipeline(PassManager &pm,
99	                                 const TargetCodegenPipelineOptions &options) {
100	  createCommonTargetCodegenPipeline<isJIT>(pm, options);
101	  if (useValueSemantics) {
102	    pm.addNestedPass<func::FuncOp>(
103	        cudaq::opt::createFactorQuantumAllocations());
104	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createDeadQuantumElimination());
105	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createCableRoughIn());
106	    pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
107	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createMemToReg());
108	    pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
109	  }
110	  ::addQIRConversionPipeline(pm, options.target);
111	  // QIR conversion may introduce cc.loop, lower to cf.
112	  cudaq::opt::addLowerToCFG(pm);
113	  cudaq::opt::ReturnToOutputLogOptions opts;
114	  // Only allow dynamic results with full QIR (local simulator targets).
115	  auto tgt = StringRef(options.target).split(':').first;
116	  opts.allowDynamicResult = tgt == "qir" || tgt == "qir-full";
117	  pm.addPass(cudaq::opt::createReturnToOutputLog(opts));
118	  pm.addPass(createConvertMathToFuncs());
119	  pm.addPass(createSymbolDCEPass());
120	  pm.addPass(cudaq::opt::createCCToLLVM());
121	}
