37	static Value packQubitSpans(Location loc, ConversionPatternRewriter &rewriter,
38	                            ValueRange operands) {
39	  auto qspanTy = cudaq::opt::getCudaqQubitSpanType(rewriter.getContext());
40	  Value newspan;
41	  if (operands.empty()) {
42	    newspan = cudaq::cc::AllocaOp::create(rewriter, loc, qspanTy);
43	    auto zero = arith::ConstantIntOp::create(rewriter, loc, 0, 64);
44	    auto nullPtrVal = cudaq::cc::CastOp::create(
45	        rewriter, loc, cudaq::opt::getCudaqQubitType(rewriter.getContext()),
46	        zero);
47	    func::CallOp::create(rewriter, loc, mlir::TypeRange{},
48	                         cudaq::opt::CudaqEMWriteToSpan,
49	                         ValueRange{newspan, nullPtrVal, zero});
50	  } else if (operands.size() == 1) {
51	    // Nothing to concatenate in this case.
52	    newspan = operands[0];
53	  } else {
54	    newspan = cudaq::cc::AllocaOp::create(rewriter, loc, qspanTy);
55	    // Loop over all arguments and count the number of qubits.
56	    Value zero = arith::ConstantIntOp::create(rewriter, loc, 0, 64);
57	    Value sum = zero;
58	    auto i64Ty = rewriter.getI64Type();
59	    auto ptrI64Ty = cudaq::cc::PointerType::get(i64Ty);
60	    for (auto v : operands) {
61	      auto sizePtr = cudaq::cc::ComputePtrOp::create(
62	          rewriter, loc, ptrI64Ty, v, ArrayRef<cudaq::cc::ComputePtrArg>{1});
63	      auto size = cudaq::cc::LoadOp::create(rewriter, loc, sizePtr);
64	      sum = arith::AddIOp::create(rewriter, loc, sum, size);
65	    }
66	    // Allocate a fresh buffer.
67	    auto newBuffer = cudaq::cc::AllocaOp::create(rewriter, loc, i64Ty, sum);
68	    func::CallOp::create(rewriter, loc, mlir::TypeRange{},
69	                         cudaq::opt::CudaqEMWriteToSpan,
70	                         ValueRange{newspan, newBuffer, sum});
71	    // Copy the i64 values to the new buffer.
72	    sum = zero;
73	    Value size = zero;
74	    for (auto v : operands) {
75	      auto dest = cudaq::cc::ComputePtrOp::create(
76	          rewriter, loc, ptrI64Ty, newBuffer,
77	          ArrayRef<cudaq::cc::ComputePtrArg>{sum});
78	      auto sizePtr = cudaq::cc::ComputePtrOp::create(
79	          rewriter, loc, ptrI64Ty, v, ArrayRef<cudaq::cc::ComputePtrArg>{1});
80	      size = cudaq::cc::LoadOp::create(rewriter, loc, sizePtr);
81	      func::CallOp::create(rewriter, loc, mlir::TypeRange{},
82	                           cudaq::opt::CudaqEMConcatSpan,
83	                           ValueRange{dest, v, size});
84	      sum = arith::AddIOp::create(rewriter, loc, sum, size);
85	    }
86	  }
87	  return newspan;
88	}
