201	class ExtractRefOpRewrite
202	    : public OpConversionPattern<cudaq::quake::ExtractRefOp> {
203	public:
204	  using OpConversionPattern::OpConversionPattern;
205	
206	  LogicalResult
207	  matchAndRewrite(cudaq::quake::ExtractRefOp extract, OpAdaptor adaptor,
208	                  ConversionPatternRewriter &rewriter) const override {
209	    auto loc = extract.getLoc();
210	    auto offset = [&]() -> Value {
211	      if (extract.hasConstantIndex())
212	        return arith::ConstantIntOp::create(rewriter, loc,
213	                                            extract.getConstantIndex(), 64);
214	      return adaptor.getIndex();
215	    }();
216	
217	    // Create our types.
218	    auto i64Ty = rewriter.getI64Type();
219	    auto ptrI64Ty = cudaq::cc::PointerType::get(i64Ty);
220	    auto arrI64Ty = cudaq::cc::ArrayType::get(i64Ty);
221	    auto ptrArrTy = cudaq::cc::PointerType::get(arrI64Ty);
222	    auto ptrptrTy = cudaq::cc::PointerType::get(ptrArrTy);
223	
224	    auto qspan = adaptor.getVeq();
225	    auto qspanDataPtr = cudaq::cc::ComputePtrOp::create(
226	        rewriter, loc, ptrptrTy, qspan, ArrayRef<cudaq::cc::ComputePtrArg>{0});
227	    auto qspanData = cudaq::cc::LoadOp::create(rewriter, loc, qspanDataPtr);
228	    auto buffer = cudaq::cc::ComputePtrOp::create(
229	        rewriter, loc, ptrI64Ty, qspanData,
230	        ArrayRef<cudaq::cc::ComputePtrArg>{offset});
231	    auto qspanTy = cudaq::opt::getCudaqQubitSpanType(rewriter.getContext());
232	    Value newspan = cudaq::cc::AllocaOp::create(rewriter, loc, qspanTy);
233	    auto one = arith::ConstantIntOp::create(rewriter, loc, 1, 64);
234	    auto buf1 = cudaq::cc::CastOp::create(rewriter, loc, ptrArrTy, buffer);
235	    func::CallOp::create(rewriter, loc, mlir::TypeRange{},
236	                         cudaq::opt::CudaqEMWriteToSpan,
237	                         ValueRange{newspan, buf1, one});
238	    rewriter.replaceOp(extract, newspan);
239	    return success();
240	  }
241	};
