243	class SubveqOpRewrite : public OpConversionPattern<cudaq::quake::SubVeqOp> {
244	public:
245	  using OpConversionPattern::OpConversionPattern;
246	
247	  // True to the semantics, this operation does not allocate a new buffer and
248	  // does not make a copy. It simply constructs a new qubit span which is a
249	  // subspan of the original.
250	  LogicalResult
251	  matchAndRewrite(cudaq::quake::SubVeqOp subveq, OpAdaptor adaptor,
252	                  ConversionPatternRewriter &rewriter) const override {
253	    auto loc = subveq.getLoc();
254	    auto up = [&]() -> Value {
255	      if (!adaptor.getUpper())
256	        return arith::ConstantIntOp::create(rewriter, loc,
257	                                            adaptor.getRawUpper(), 64);
258	      return adaptor.getUpper();
259	    }();
260	    auto lo = [&]() -> Value {
261	      if (!adaptor.getLower())
262	        return arith::ConstantIntOp::create(rewriter, loc,
263	                                            adaptor.getRawLower(), 64);
264	      return adaptor.getLower();
265	    }();
266	    auto diff = arith::SubIOp::create(rewriter, loc, up, lo);
267	    auto one = arith::ConstantIntOp::create(rewriter, loc, 1, 64);
268	    auto length = arith::AddIOp::create(rewriter, loc, diff, one);
269	    // Compute the pointer to the first element in the subveq and build a new
270	    // array type.
271	    auto i64Ty = rewriter.getI64Type();
272	    auto ptrI64Ty = cudaq::cc::PointerType::get(i64Ty);
273	    auto ptrTy = cudaq::cc::PointerType::get(cudaq::cc::ArrayType::get(i64Ty));
274	    auto ptrptrTy = cudaq::cc::PointerType::get(ptrTy);
275	    auto qspanDataPtr = cudaq::cc::ComputePtrOp::create(
276	        rewriter, loc, ptrptrTy, adaptor.getVeq(),
277	        ArrayRef<cudaq::cc::ComputePtrArg>{0});
278	    auto qspanData = cudaq::cc::LoadOp::create(rewriter, loc, qspanDataPtr);
279	    auto buffer =
280	        cudaq::cc::ComputePtrOp::create(rewriter, loc, ptrI64Ty, qspanData,
281	                                        ArrayRef<cudaq::cc::ComputePtrArg>{lo});
282	    auto qspanTy = cudaq::opt::getCudaqQubitSpanType(rewriter.getContext());
283	    Value newspan = cudaq::cc::AllocaOp::create(rewriter, loc, qspanTy);
284	    func::CallOp::create(rewriter, loc, mlir::TypeRange{},
285	                         cudaq::opt::CudaqEMWriteToSpan,
286	                         ValueRange{newspan, buffer, length});
287	    rewriter.replaceOp(subveq, newspan);
288	    return success();
289	  }
290	};
