309	  using Base = OpConversionPattern<OP>;
310	  using Base::Base;
311	
312	  LogicalResult
313	  matchAndRewrite(OP qop, typename Base::OpAdaptor adaptor,
314	                  ConversionPatternRewriter &rewriter) const override {
315	    auto loc = qop.getLoc();
316	    auto instName = qop->getName().stripDialect().str();
317	    auto mod = qop->template getParentOfType<ModuleOp>();
318	    auto opName = createOpName(loc, mod, rewriter, instName);
319	    auto i8Ty = rewriter.getI8Type();
320	    auto ptrI8Ty = cudaq::cc::PointerType::get(i8Ty);
321	    auto regTy = cudaq::cc::PointerType::get(opName.getType());
322	    auto addr = cudaq::cc::AddressOfOp::create(rewriter, loc, regTy,
323	                                               opName.getSymName());
324	    auto opString = cudaq::cc::CastOp::create(rewriter, loc, ptrI8Ty, addr);
325	    auto paramSize = adaptor.getParameters().size();
326	    Value numParams =
327	        arith::ConstantIntOp::create(rewriter, loc, paramSize, 64);
328	    auto f64Ty = rewriter.getF64Type();
329	    auto arrF64Ty = cudaq::cc::ArrayType::get(f64Ty);
330	    auto ptrParamTy = cudaq::cc::PointerType::get(arrF64Ty);
331	    auto ptrF64Ty = cudaq::cc::PointerType::get(f64Ty);
332	    auto params = [&]() -> Value {
333	      if (paramSize == 0) {
334	        auto zero = arith::ConstantIntOp::create(rewriter, loc, paramSize, 64);
335	        return cudaq::cc::CastOp::create(rewriter, loc, ptrParamTy, zero);
336	      }
337	      auto buffer =
338	          cudaq::cc::AllocaOp::create(rewriter, loc, f64Ty, numParams);
339	      for (auto iter : llvm::enumerate(adaptor.getParameters())) {
340	        std::int32_t i = iter.index();
341	        auto p = iter.value();
342	        auto ptr = cudaq::cc::ComputePtrOp::create(
343	            rewriter, loc, ptrF64Ty, buffer,
344	            ArrayRef<cudaq::cc::ComputePtrArg>{i});
345	        cudaq::cc::StoreOp::create(rewriter, loc, p, ptr);
346	      }
347	      return buffer;
348	    }();
349	    auto controls = packQubitSpans(loc, rewriter, adaptor.getControls());
350	    auto targets = packQubitSpans(loc, rewriter, adaptor.getTargets());
351	    auto isAdj = [&]() -> Value {
352	      if (qop.isAdj())
353	        return arith::ConstantIntOp::create(rewriter, loc, 1, 1);
354	      return arith::ConstantIntOp::create(rewriter, loc, 0, 1);
355	    }();
356	    rewriter.template replaceOpWithNewOp<func::CallOp>(
357	        qop, mlir::TypeRange{}, cudaq::opt::CudaqEMApply,
358	        ValueRange{opString, numParams, params, controls, targets, isAdj});
359	    return success();
360	  }
361	
362	  // Create a global with the "name" to use for this operation.
363	  LLVM::GlobalOp createOpName(Location loc, ModuleOp mod,
364	                              ConversionPatternRewriter &rewriter,
365	                              StringRef name) const {
366	    OpBuilder::InsertionGuard guard(rewriter);
367	    auto builder = cudaq::IRBuilder::atBlockEnd(mod.getBody());
368	    return builder.genCStringLiteralAppendNul(loc, mod, name.str());
369	  }
370	};
371	
372	class MzOpRewrite : public OpConversionPattern<cudaq::quake::MzOp> {
373	public:
374	  using OpConversionPattern::OpConversionPattern;
375	
376	  // Create a global with the "name" to use for this measurement.
377	  LLVM::GlobalOp createRegisterName(Location loc, ModuleOp mod,
378	                                    ConversionPatternRewriter &rewriter,
379	                                    StringAttr nameAttr) const {
380	    std::string mzName;
381	    if (nameAttr) {
382	      mzName = nameAttr.getValue().str();
383	    } else {
384	      // No name was given. Use a hash based on the source file location of the
385	      // measurement operation, to give something that ought to be relatively
386	      // unique.
387	      std::size_t hash = mlir::hash_value(loc);
388	      hash = (hash ^ (hash >> 16)) & 0xFFFF;
389	      mzName = std::string("r") + std::to_string(hash);
390	    }
391	    OpBuilder::InsertionGuard guard(rewriter);
392	    auto builder = cudaq::IRBuilder::atBlockEnd(mod.getBody());
393	    return builder.genCStringLiteralAppendNul(loc, mod, mzName);
394	  }
395	
396	  LogicalResult
397	  matchAndRewrite(cudaq::quake::MzOp mzOp, OpAdaptor adaptor,
398	                  ConversionPatternRewriter &rewriter) const override {
399	    auto loc = mzOp.getLoc();
400	    auto mod = mzOp->getParentOfType<ModuleOp>();
401	    auto regName =
402	        createRegisterName(loc, mod, rewriter, mzOp.getRegisterNameAttr());
403	    auto i8Ty = rewriter.getI8Type();
404	    auto ptrI8Ty = cudaq::cc::PointerType::get(i8Ty);
405	    auto regTy = cudaq::cc::PointerType::get(regName.getType());
406	    auto addr = cudaq::cc::AddressOfOp::create(rewriter, loc, regTy,
407	                                               regName.getSymName());
408	    auto nameAddr = cudaq::cc::CastOp::create(rewriter, loc, ptrI8Ty, addr);
409	    auto i32Ty = rewriter.getI32Type();
410	    rewriter.replaceOpWithNewOp<func::CallOp>(
411	        mzOp, i32Ty, cudaq::opt::CudaqEMMeasure,
412	        ValueRange{adaptor.getTargets()[0], nameAddr});
413	    return success();
414	  }
415	};
416	
417	/// Convert a MX operation to a sequence H; MZ.
418	class MxToMzRewrite : public OpRewritePattern<cudaq::quake::MxOp> {
419	public:
420	  using OpRewritePattern::OpRewritePattern;
421	
422	  LogicalResult matchAndRewrite(cudaq::quake::MxOp mx,
423	                                PatternRewriter &rewriter) const override {
424	    cudaq::quake::HOp::create(rewriter, mx.getLoc(), mx.getTargets());
425	    rewriter.replaceOpWithNewOp<cudaq::quake::MzOp>(
426	        mx, mx.getResultTypes(), mx.getTargets(), mx.getRegisterNameAttr());
427	    return success();
428	  }
429	};
430	
431	/// Convert a MY operation to a sequence S; H; MZ.
432	class MyToMzRewrite : public OpRewritePattern<cudaq::quake::MyOp> {
433	public:
434	  using OpRewritePattern::OpRewritePattern;
435	
436	  LogicalResult matchAndRewrite(cudaq::quake::MyOp my,
437	                                PatternRewriter &rewriter) const override {
438	    cudaq::quake::SOp::create(rewriter, my.getLoc(), true, ValueRange{},
439	                              ValueRange{}, my.getTargets());
440	    cudaq::quake::HOp::create(rewriter, my.getLoc(), my.getTargets());
441	    rewriter.replaceOpWithNewOp<cudaq::quake::MzOp>(
442	        my, my.getResultTypes(), my.getTargets(), my.getRegisterNameAttr());
443	    return success();
444	  }
445	};
446	
447	class VeqSizeOpRewrite : public OpConversionPattern<cudaq::quake::VeqSizeOp> {
448	public:
449	  using OpConversionPattern::OpConversionPattern;
450	
451	  LogicalResult
452	  matchAndRewrite(cudaq::quake::VeqSizeOp vecsize, OpAdaptor adaptor,
453	                  ConversionPatternRewriter &rewriter) const override {
454	    auto loc = vecsize->getLoc();
455	    auto i64Ty = rewriter.getI64Type();
456	    auto ptrI64Ty = cudaq::cc::PointerType::get(i64Ty);
457	    auto sizeptr = cudaq::cc::ComputePtrOp::create(
458	        rewriter, loc, ptrI64Ty, adaptor.getVeq(),
459	        ArrayRef<cudaq::cc::ComputePtrArg>{1});
460	    rewriter.replaceOpWithNewOp<cudaq::cc::LoadOp>(vecsize, sizeptr);
461	    return success();
462	  }
463	};
464	
465	} // namespace
466	
467	void cudaq::opt::populateQuakeToCCPatterns(TypeConverter &converter,
468	                                           RewritePatternSet &patterns) {
469	  auto *context = patterns.getContext();
470	  patterns.insert<
471	      AllocaOpRewrite, ConcatOpRewrite, DeallocOpRewrite, DiscriminateOpRewrite,
472	      ExtractRefOpRewrite, VeqSizeOpRewrite, MzOpRewrite, ResetRewrite,
473	      SubveqOpRewrite, GenericRewrite<cudaq::quake::HOp>,
474	      GenericRewrite<cudaq::quake::PhasedRxOp>,
475	      GenericRewrite<cudaq::quake::R1Op>, GenericRewrite<cudaq::quake::RxOp>,
476	      GenericRewrite<cudaq::quake::RyOp>, GenericRewrite<cudaq::quake::RzOp>,
477	      GenericRewrite<cudaq::quake::SOp>, GenericRewrite<cudaq::quake::SwapOp>,
478	      GenericRewrite<cudaq::quake::TOp>, GenericRewrite<cudaq::quake::U2Op>,
479	      GenericRewrite<cudaq::quake::U3Op>, GenericRewrite<cudaq::quake::XOp>,
480	      GenericRewrite<cudaq::quake::YOp>, GenericRewrite<cudaq::quake::ZOp>>(
481	      converter, context);
482	}
483	
484	void cudaq::opt::populateQuakeToCCPrepPatterns(RewritePatternSet &patterns) {
485	  patterns.insert<MxToMzRewrite, MyToMzRewrite>(patterns.getContext());
486	}
