      args.push_back(castedRegNameRef);

    FlatSymbolRefAttr symbolRef = cudaq::opt::factory::createLLVMFunctionSymbol(
        qFunctionName, cudaq::cg::getLLVMResultType(context),
        llvm::ArrayRef(funcTypes), parentModule);

