36	void validateOutputRecord(
37	    const std::vector<std::string> &entries,
38	    const std::optional<cudaq::RecordSchemaType> &declaredSchema) {
39	  if (entries.size() < 3 || entries.size() > 4)
40	    throw std::runtime_error("Invalid OUTPUT record");
41	  if (declaredSchema.has_value()) {
42	    const std::size_t expectedFields =
43	        declaredSchema.value() == cudaq::RecordSchemaType::LABELED ? 4 : 3;
44	    if (entries.size() != expectedFields)
45	      throw std::runtime_error("Unexpected record size for schema");
46	  }
47	}
