50	void cudaq::RecordLogParser::parse(const std::string &outputLog) {
51	  ScopedTraceWithContext(cudaq::TIMING_RUN, "RecordLogParser::parse");
52	  CUDAQ_DBG("Parsing log:\n{}", outputLog);
53	  std::vector<std::string> lines = cudaq::split(outputLog, '\n');
54	  if (lines.empty())
55	    return;
56	
57	  // Collect log from a single shot and process it only if it is successful.
58	  bool processingShot = false;
59	  // Track whether we have seen framed output (between START and END) or not
60	  bool sawFramedOutput = false;
61	  bool sawUnframedOutput = false;
62	  bool sawOutput = false;
63	  // Keep explicit declarations separate: `schema` is also inferred from
64	  // legacy labeled container records.
65	  std::optional<RecordSchemaType> declaredSchema;
66	  // Maintain the starting index of each shot's data
67	  std::size_t shotStart = 0;
68	
69	  for (std::size_t idx = 0; idx < lines.size(); ++idx) {
70	    const auto &line = lines[idx];
71	    std::vector<std::string> entries = cudaq::split(line, '\t');
72	    if (entries.empty())
73	      continue;
74	
75	    const std::string &recordType = entries[0];
76	    if (recordType == "HEADER") {
77	      if (sawOutput)
78	        throw std::runtime_error("HEADER record after output");
79	      handleHeader(entries, declaredSchema);
80	    } else if (recordType == "METADATA")
81	      handleMetadata(entries);
82	    else if (recordType == "START") {
83	      if (entries.size() != 1)
84	        throw std::runtime_error("Invalid START record");
85	      if (processingShot)
86	        throw std::runtime_error("Nested START record");
87	      if (sawUnframedOutput)
88	        throw std::runtime_error("Mixed framed and unframed output");
89	      processingShot = true;
90	      shotStart = 0;
91	    } else if (recordType == "OUTPUT") {
92	      validateOutputRecord(entries, declaredSchema);
93	      sawOutput = true;
94	      if (processingShot) {
95	        sawFramedOutput = true;
96	        shotStart = shotStart == 0 ? idx : shotStart;
97	      } else {
98	        if (sawFramedOutput)
99	          throw std::runtime_error("Mixed framed and unframed output");
100	        sawUnframedOutput = true;
101	        handleOutput(entries);
102	      }
103	    } else if (recordType == "END") {
104	      if (entries.size() != 2)
105	        throw std::runtime_error("Invalid END record");
106	      if (!processingShot)
107	        throw std::runtime_error("END record without START");
108	      if (detail::parseSize(entries[1]) == 0) {
109	        if (processingShot) {
110	          // Successful shot, process it
111	          for (std::size_t j = shotStart; j < idx; ++j)
112	            handleOutput(cudaq::split(lines[j], '\t'));
113	        }
114	      } else {
115	        CUDAQ_DBG("Discarding shot data due to non-zero END status.");
116	      }
117	      processingShot = false;
118	      shotStart = 0;
119	      containerMeta.reset();
120	    } else {
121	      throw std::runtime_error("Invalid record type: " + recordType);
122	    }
123	  }
124	
125	  if (processingShot)
126	    throw std::runtime_error("Unterminated shot");
127	}
