150	void cudaq::RecordLogParser::handleMetadata(
151	    const std::vector<std::string> &entries) {
152	  if (entries.size() < 2 || entries.size() > 3)
153	    throw std::runtime_error("Invalid METADATA record");
154	  if (entries.size() == 3) {
155	    if (entries[1] == cudaq::opt::qir1_0::RequiredResultsAttrName ||
156	        entries[1] == cudaq::opt::qir0_1::RequiredResultsAttrName) {
157	      detail::parseSize(entries[2]);
158	      metadata[ResultCountMetadataName] = entries[2];
159	    } else {
160	      metadata[entries[1]] = entries[2];
161	    }
162	  } else {
163	    metadata[entries[1]] = "";
164	  }

